    41→/*
    42→ * Requires:
    43→ *   The parameter "uri" must point to a properly NUL-terminated string.
    44→ *
    45→ * Effects:
    46→ *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
    47→ *   host name, port, and path name.  Create strings containing the host name,
    48→ *   port, and path name, and return them through the parameters "hostnamep",
    49→ *   "portp", "pathnamep", respectively.  (The caller must free the memory
    50→ *   storing these strings.)  Return -1 if there are any problems and 0
    51→ *   otherwise.
    52→ */
    53→static int
    54→parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
    55→{
    56→	const char *pathname_begin, *port_begin, *port_end;
    57→
    58→	if (strncasecmp(uri, "http://", 7) != 0)
    59→		return (-1);
    60→
    61→	/* Extract the host name. */
    62→	const char *host_begin = uri + 7;
    63→	const char *host_end = strpbrk(host_begin, ":/ \r\n");
    64→	if (host_end == NULL)
    65→		host_end = host_begin + strlen(host_begin);
    66→	int len = host_end - host_begin;
    67→	char *hostname = Malloc(len + 1);
    68→	strncpy(hostname, host_begin, len);
    69→	hostname[len] = '\0';
    70→	*hostnamep = hostname;
    71→
    72→	/* Look for a port number.  If none is found, use port 80. */
    73→	if (*host_end == ':') {
    74→		port_begin = host_end + 1;
    75→		port_end = strpbrk(port_begin, "/ \r\n");
    76→		if (port_end == NULL)
    77→			port_end = port_begin + strlen(port_begin);
    78→		len = port_end - port_begin;
    79→	} else {
    80→		port_begin = "80";
    81→		port_end = host_end;
    82→		len = 2;
    83→	}
    84→	char *port = Malloc(len + 1);
    85→	strncpy(port, port_begin, len);
    86→	port[len] = '\0';
    87→	*portp = port;
    88→
    89→	/* Extract the path. */
    90→	if (*port_end == '/') {
    91→		pathname_begin = port_end;
    92→		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
    93→		if (pathname_end == NULL)
    94→			pathname_end = pathname_begin + strlen(pathname_begin);
    95→		len = pathname_end - pathname_begin;
    96→	} else {
    97→		pathname_begin = "/";
    98→		len = 1;
    99→	}
   100→	char *pathname = Malloc(len + 1);
   101→	strncpy(pathname, pathname_begin, len);
   102→	pathname[len] = '\0';
   103→	*pathnamep = pathname;
   104→
   105→	return (0);
   106→}
