   160→/*
   161→ * Requires:
   162→ *   The parameter "fd" must be an open socket that is connected to the client.
   163→ *   The parameters "cause", "short_msg", and "long_msg" must point to properly 
   164→ *   NUL-terminated strings that describe the reason why the HTTP transaction
   165→ *   failed.  The string "short_msg" may not exceed 32 characters in length,
   166→ *   and the string "long_msg" may not exceed 80 characters in length.
   167→ *
   168→ * Effects:
   169→ *   Constructs an HTML page describing the reason why the HTTP transaction
   170→ *   failed, and writes an HTTP/1.0 response containing that page as the
   171→ *   content.  The cause appearing in the HTML page is truncated if the
   172→ *   string "cause" exceeds 2048 characters in length.
   173→ */
   174→static void
   175→client_error(int fd, const char *cause, int err_num, const char *short_msg,
   176→    const char *long_msg)
   177→{
   178→	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];
   179→
   180→	assert(strlen(short_msg) <= 32);
   181→	assert(strlen(long_msg) <= 80);
   182→	/* Ensure that "body" is much larger than "truncated_cause". */
   183→	assert(sizeof(truncated_cause) < MAXBUF / 2);
   184→
   185→	/*
   186→	 * Create a truncated "cause" string so that the response body will not
   187→	 * exceed MAXBUF.
   188→	 */
   189→	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
   190→	truncated_cause[sizeof(truncated_cause) - 1] = '\0';
   191→
   192→	/* Build the HTTP response body. */
   193→	snprintf(body, MAXBUF,
   194→	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
   195→	    "%d: %s\r\n"
   196→	    "<p>%s: %s\r\n"
   197→	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
   198→	    err_num, short_msg, long_msg, truncated_cause);
   199→
   200→	/* Build the HTTP response headers. */
   201→	snprintf(headers, MAXBUF,
   202→	    "HTTP/1.0 %d %s\r\n"
   203→	    "Content-type: text/html\r\n"
   204→	    "Content-length: %d\r\n"
   205→	    "\r\n",
   206→	    err_num, short_msg, (int)strlen(body));
   207→
   208→	/* Write the HTTP response. */
   209→	if (rio_writen(fd, headers, strlen(headers)) != -1)
   210→		rio_writen(fd, body, strlen(body));
   211→}
