   135→ssize_t rio_writen(int fd, void *usrbuf, size_t n) {
   136→    size_t nleft = n;
   137→    ssize_t nwritten;
   138→    char *bufp = usrbuf;
   139→
   140→    while (nleft > 0) {
   141→        if ((nwritten = write(fd, bufp, nleft)) <= 0) {
   142→            if (errno == EINTR)
   143→                nwritten = 0;
   144→            else
   145→                return -1;
   146→        }
   147→        nleft -= nwritten;
   148→        bufp += nwritten;
